let fs=require("fs"),path=require("path"),{package_info,locale_dir,source_dir}=require(path.join(path.dirname(path.dirname(__dirname)),"_package.js")),exec=require("child_process").exec,entries=fs.readdirSync(locale_dir,{withFileTypes:!0}),package_langs=entries.filter(e=>e.isDirectory()).map(e=>e.name);package_langs.forEach(e=>{let o=path.join(locale_dir,e,"LC_MESSAGES",package_info.name+".po");if(fs.existsSync(o)){let i=path.join(locale_dir,e,"LC_MESSAGES",package_info.name+".mo");e=`      msgfmt -vv -o ${i} ${o}
    `;exec(e,(e,a,r)=>{e?console.error(`Error generating "${i}" from "${o}"`):console.log(`Generating ${i} from "${o}" .`)})}});